{
    "instance_id": "",
    "data": {
        "contact": {
            "name": "Ritesh Kumar",
            "email": "user@example.com",
            "phone": "+1-555-0100"
        },
        "trigger": {
            "type": "manual",
            "payload": {}
        }
    },
    "workflow": {
        "id": "email-track-workflow",
        "task_queue": "approval-task-queue",
        "steps": [
            {
                "id": 0,
                "type": "wait",
                "from": "trigger",
                "to": 1,
                "wait_duration": "3s"
            },
            {
                "id": 1,
                "type": "sendEmail",
                "from": 0,
                "to": 2,
                "properties": {
                    "toEmail": "{{contact.email}}",
                    "subject": "Hello from Temporal",
                    "body": "Hi {{contact.name}}, please open this email to continue."
                }
            },
            {
                "id": 2,
                "type": "waitForEvent",
                "from": 1,
                "on_event": 11,
                "on_timeout": 12,
                "event_type": "email-open",
                "timeout": "1m"
            },
            {
                "id": 11,
                "type": "wait",
                "from": 2,
                "to": 3,
                "wait_duration": "10s"
            },
            {
                "id": 12,
                "type": "wait",
                "from": 2,
                "to": 4,
                "wait_duration": "10s"
            },
            {
                "id": 3,
                "type": "sendEmail",
                "from": 11,
                "to": null,
                "properties": {
                    "toEmail": "{{contact.email}}",
                    "subject": "Thanks for opening!",
                    "body": "Hi {{contact.name}}, Thanks for Opening the Email."
                }
            },
            {
                "id": 4,
                "type": "sendEmail",
                "from": 12,
                "to": null,
                "properties": {
                    "toEmail": "{{contact.email}}",
                    "subject": "We missed you",
                    "body": "Hi {{contact.name}}, we noticed you did not open our previous email."
                }
            }
        ]
    }
}

